// ❌ BAD - verbose block body for trivially simple members
public class Invoice {
    public decimal SubTotal { get; }
    public decimal Tax { get; }
    public decimal Total { get { return SubTotal + Tax; } }
    public override string ToString() { return $"Invoice {Total:C}"; }
}

// ✅ GOOD - expression-bodied members: concise, readable
public class Invoice {
    public decimal SubTotal { get; }
    public decimal Tax { get; }
    public Invoice(decimal sub, decimal tax) => (SubTotal, Tax) = (sub, tax);
    public decimal Total => SubTotal + Tax;
    public override string ToString() => $"Invoice {Total:C}";
}

// ❌ BAD - List<T> is invariant; this does not compile
List<Dog> dogs = new List<Dog>();
List<Animal> animals = dogs; // compile error

// ✅ GOOD - IEnumerable<out T> is covariant; IEnumerable<Dog> as IEnumerable<Animal>
IEnumerable<Dog> dogs = new List<Dog> { new Dog() };
IEnumerable<Animal> animals = dogs; // valid - T is covariant (out)

// Contravariance: Action<in T>
Action<Animal> feedAnimal = a => Console.WriteLine($"Feeding {a.Name}");
Action<Dog> feedDog = feedAnimal; // valid - any Animal handler handles a Dog

// ❌ BAD - dynamic used for a known type; loses all safety and IntelliSense
dynamic order = GetOrder();
var total = order.Totla; // typo in property name - compiles, crashes at runtime

// ✅ GOOD - dynamic used where compile-time type is genuinely unknown (COM interop)
// Excel COM interop: Excel type lib not available at compile time
dynamic excelApp = Activator.CreateInstance(Type.GetTypeFromProgID("Excel.Application"));
excelApp.Visible = true;
excelApp.Workbooks.Add();
// This is one of the few places dynamic is the right tool

// ❌ BAD - IOptionsSnapshot injected into a singleton = captive dependency
public class EmailSender { // singleton
    public EmailSender(IOptionsSnapshot<SmtpOptions> opts) { } // scoped into singleton - wrong
}

// ✅ GOOD - IOptions in singleton; IOptionsMonitor for live reload in singleton
builder.Services.Configure<SmtpOptions>(builder.Configuration.GetSection("Smtp"));
// In a singleton that needs live reload:
public class EmailSender {
    private readonly IOptionsMonitor<SmtpOptions> _opts;
    public EmailSender(IOptionsMonitor<SmtpOptions> opts) => _opts = opts;
    public SmtpOptions Current => _opts.CurrentValue;
}

// ❌ BAD - editing a generated file; changes wiped on next regeneration
// File: Customer.g.cs (generated)
public class Customer { public int Id { get; set; } public string Name { get; set; } }
// Developer adds logic here - it will be overwritten

// ✅ GOOD - partial class separates generated from hand-written code
// File: Customer.g.cs (generated - do not edit)
public partial class Customer { public int Id { get; set; } }
// File: Customer.cs (hand-written - safe to edit)
public partial class Customer {
    public string DisplayName => $"Customer #{Id}";
    partial void OnValidate(); // optional hook
}
